package genxsolution.vms.vmsbackend.maintenance_management.maintenance_standard.service;
import genxsolution.vms.vmsbackend.maintenance_management.exception.MaintenanceResourceNotFoundException; import genxsolution.vms.vmsbackend.maintenance_management.maintenance_standard.dto.*; import genxsolution.vms.vmsbackend.maintenance_management.maintenance_standard.mapper.MaintenanceStandardMapper; import genxsolution.vms.vmsbackend.maintenance_management.maintenance_standard.repository.MaintenanceStandardRepository; import org.springframework.stereotype.Service; import java.util.*;
@Service public class MaintenanceStandardService { private final MaintenanceStandardRepository repository; private final MaintenanceStandardMapper mapper; public MaintenanceStandardService(MaintenanceStandardRepository repository,MaintenanceStandardMapper mapper){this.repository=repository;this.mapper=mapper;} public List<MaintenanceStandardResponse> list(UUID companyId){ return repository.findAll(companyId).stream().map(mapper::toResponse).toList(); } public MaintenanceStandardResponse getById(UUID id){ return repository.findById(id).map(mapper::toResponse).orElseThrow(() -> new MaintenanceResourceNotFoundException("MaintenanceStandard", String.valueOf(id))); } public MaintenanceStandardResponse create(MaintenanceStandardUpsertRequest r){ return mapper.toResponse(repository.create(r)); } public MaintenanceStandardResponse update(UUID id,MaintenanceStandardUpsertRequest r){ return repository.update(id,r).map(mapper::toResponse).orElseThrow(() -> new MaintenanceResourceNotFoundException("MaintenanceStandard", String.valueOf(id))); } public void delete(UUID id){ if(!repository.delete(id)) throw new MaintenanceResourceNotFoundException("MaintenanceStandard", String.valueOf(id)); } }
